mapper.select:
select l.id as linkId, l.visit_kind as visitKind, l.mirror_row_id as mirrorRowId, l.alloc_qty as allocQty, l.dept_batch_consume_entry_id as deptBatchConsumeEntryId, l.in_hospital_code as inHospitalCode, ifnull(l.confirm_status, 0) as confirmStatus, l.confirm_id as confirmId, c.confirm_no as confirmNo, in_bill.bill_no as inboundBillNo, out_bill.bill_no as outboundBillNo, t.create_time as consumeCreateTime, cast(t.audit_date as datetime) as consumeAuditDate, () as consumeAuditTime, t.trace_no as consumeBillNo, te.id as consumeEntryId, te.material_id as materialId, te.material_name as materialName, te.charge_price as unitPrice, coalesce(l.alloc_qty, te.quantity) as entryQty, case when te.charge_price is not null and coalesce(l.alloc_qty, te.quantity) is not null then te.charge_price * coalesce(l.alloc_qty, te.quantity) else null end as amt, cast(te.supplier_id as char) as supplierId, sup.name as supplierName, te.batch_no as batchNo, t.exec_dept_id as departmentId, d.name as departmentName, coalesce(inp.patient_name, outp.patient_name) as patientName, coalesce(inp.inpatient_no, outp.outpatient_no) as visitNo, coalesce(inp.charge_item_id, outp.charge_item_id) as chargeItemId, coalesce(inp.item_name, outp.item_name) as itemName, coalesce( nullif(trim(inp.spec_model), ''), nullif(trim(outp.spec_model), ''), (select cm.speci from fd_material cm where cm.tenant_id = l.tenant_id and trim(cm.his_charge_item_id) = trim(coalesce(inp.charge_item_id, outp.charge_item_id)) and (cm.del_flag = 0 or cm.del_flag is null) order by cm.id limit 1) ) as itemSpec, (select cm.model from fd_material cm where cm.tenant_id = l.tenant_id and trim(cm.his_charge_item_id) = trim(coalesce(inp.charge_item_id, outp.charge_item_id)) and (cm.del_flag = 0 or cm.del_flag is null) order by cm.id limit 1) as itemModel
and t.exec_dept_id = #{departmentId}
and ifnull(l.confirm_status, 0) = #{confirmStatus}
and () >= #{beginConsumeAuditTime}
and () <= #{endConsumeAuditTime}
and coalesce(inp.patient_name, outp.patient_name) like concat('%', #{patientName}, '%')
and coalesce(inp.inpatient_no, outp.outpatient_no) like concat('%', #{visitNo}, '%')
and coalesce(inp.charge_item_id, outp.charge_item_id) like concat('%', #{chargeItemId}, '%')
and te.material_name like concat('%', #{materialName}, '%')
order by consumeAuditTime desc, l.id desc

mapper.insert:
insert into gz_high_consume_confirm (
    id, tenant_id, confirm_no, department_id, warehouse_id,
    confirm_time, confirm_by, period_begin, period_end, remark,
    del_flag, create_by, create_time
) values (
    #{id}, #{tenantId}, #{confirmNo}, #{departmentId}, #{warehouseId},
    #{confirmTime}, #{confirmBy}, #{periodBegin}, #{periodEnd}, #{remark},
    ifnull(#{delFlag}, 0), #{createBy}, #{createTime}
)
